import{_ as t,o as n,c as a,a3 as o}from"./chunks/framework.CjquFG0V.js";const g=JSON.parse('{"title":"87. Secure Employment Agency Staff And Bank Employees","description":"","frontmatter":{"title":"87. Secure Employment Agency Staff And Bank Employees","eba":"Nurses and Midwives 2024-2028","topics":["leave","annual-leave","parental-leave","long-service-leave"]},"headers":[],"relativePath":"ebas/nurses-midwives/classification-staffing/87-secure-employment-agency-staff-and-bank-employees.md","filePath":"ebas/nurses-midwives/classification-staffing/87-secure-employment-agency-staff-and-bank-employees.md"}'),s={name:"ebas/nurses-midwives/classification-staffing/87-secure-employment-agency-staff-and-bank-employees.md"};function r(i,e,l,p,c,m){return n(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="_87-secure-employment-agency-staff-and-bank-employees" tabindex="-1">87. Secure Employment Agency Staff And Bank Employees <a class="header-anchor" href="#_87-secure-employment-agency-staff-and-bank-employees" aria-label="Permalink to &quot;87. Secure Employment Agency Staff And Bank Employees&quot;">​</a></h1><p><strong>87.1</strong> Replacement during Annual Leave and Extended Leave Relief</p><p><strong>(a)</strong> In order to maintain the nursing hours provided by the Safe Patient Care Act, the rostered hours of all Employees who are on Extended Leave will be fully replaced.</p><p><strong>(b)</strong> Extended Leave includes long service leave, parental leave, and long-term WorkCover absences.</p><p><strong>(c)</strong> In all ward/unit/department budgets, provision will be made for the payment of salaries to persons employed to replace Employees who are absent due to annual leave.</p><p><strong>87.2</strong> Agency Staff and Bank Employees</p><p><strong>(a)</strong> The Employer acknowledges the positive impact that secure employment has on Employees and the provision of quality services to the Victorian community.</p><p><strong>(b)</strong> The Employer will give preference to ongoing forms of employment over casual and fixed term arrangements wherever possible. Agency or labour hire employees should not be used to undermine the job security of direct Employees and should only be relied on in limited circumstances.</p><p><strong>(c)</strong> Limiting the use of agency labour is consistent with the commitment to maintain public sector employment. Each Employer will seek to maximise its use of part- time and full-time Employees in meeting its nursing and midwifery staffing needs and its Safe Patient Care Act obligations.</p><p><strong>(d)</strong> Arrangements that support this commitment include:</p><p><strong>(i)</strong> budgets that contemplate replacement of staff;</p><p><strong>(ii)</strong> sufficiently resourced Pool Employee arrangements;</p><p><strong>(iii)</strong> technology that supports the identification of labour requirements, budget and roster building; and</p><p><strong>(iv)</strong> processes to support and encourage the conversion from casual to permanent employment.</p><p><strong>(e)</strong> Actions by the Employer to promote secure employment, including the matters listed at (d) above, will be discussed by the WIC.</p><p><strong>87.3</strong> Filling/Advertisement of Position</p><p><strong>(a)</strong> The process for advertising and filling of vacancies will be as follows:</p><p><strong>(i)</strong> each ward/clinical unit will have a nurse/midwife staffing profile based on EFT Employees;</p><p><strong>(ii)</strong> where a vacancy arises within that nurse/midwife staffing profile, the responsible manager/nurse-in-charge will initiate action to advertise the vacant position internally and/or externally immediately after receiving notice of resignation or termination; and</p><p><strong>(iii)</strong> the Employer will advertise all ward-based vacancies that arise where the vacancy relates to a position that but for the vacancy occurring would have been ongoing, as soon as practicable (ordinarily within eight working days).</p><p><strong>(b)</strong> Any notice, circular or advertisement for a position regulated by this Agreement will specify the salary grade or sub-grade applicable.</p>',21)])])}const f=t(s,[["render",r]]);export{g as __pageData,f as default};
